sect1.programlisting:
FOO_LAYOUT := RECORD
    UTF8 foo {XPATH('foo')};
    UNSIGNED start {XPATH('start')};
    REAL f_end {XPATH('end')};
END;

// ds := DATASET('~data::foo', FOO_LAYOUT, JSON());

// Generated layout from json2ecl
FOO_LAYOUT := RECORD
    UTF8 foo {XPATH('foo')};
    UNSIGNED start {XPATH('start')};
    REAL f_end {XPATH('end')};
END;

// Use the layout to read JSON data
ds := DATASET('~data::foo', FOO_LAYOUT, JSON());

// Nested JSON layout example
PERSON_LAYOUT := RECORD
    UTF8 firstName {XPATH('firstName')};
    UTF8 lastName {XPATH('lastName')};
    UNSIGNED age {XPATH('age')};
    DATASET(ADDRESS_REC) addresses {XPATH('addresses')};
END;

// Read the JSON file
people := DATASET('~data::people', PERSON_LAYOUT, JSON());

sect1.para:
ECL record structures generated by xml2ecl can be used with ECL's
      DATASET declaration using the XML() format or with the PARSE
      function:

sect1.programlisting:
// Using DATASET with XML() format
CUSTOMER_LAYOUT := RECORD
    UTF8 id {XPATH('@id')};
    UTF8 FirstName {XPATH('FirstName')};
    UTF8 LastName {XPATH('LastName')};
    UNSIGNED Age {XPATH('Age')};
END;

// Read XML file
customers := DATASET('~data::customers.xml', 
                     CUSTOMER_LAYOUT, 
                     XML('Customer'));

// Read the raw XML file
xmlFile := DATASET('~data::customers.xml', 
                   {STRING line}, 
                   CSV(SEPARATOR(''), QUOTE('')));

// Parse XML data
parsedCustomers := PARSE(xmlFile, 
                         line, 
                         CUSTOMER_LAYOUT, 
                         XML('Customer'));

OUTPUT(parsedCustomers);
